// SPDX-License-Identifier: Apache-2.0
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "./NexusToken.sol";

/**
 * @title NexusBridge
 * @dev Cross-currency swap and bridge contract for Nexus Pay
 * Handles tokenized currency swaps with yield generation
 */
contract NexusBridge is ReentrancyGuard, Ownable {

    // Token registry
    mapping(string => address) public currencyTokens; // "MXN" => NexusToken address
    mapping(address => string) public tokenCurrencies; // NexusToken address => "MXN"

    // Exchange rates (set by oracle in production)
    mapping(string => mapping(string => uint256)) public exchangeRates; // fromCurrency => toCurrency => rate (scaled by 1e8)

    // Fee structure
    uint256 public protocolFee = 50; // 0.5% (in basis points)
    uint256 public constant FEE_DENOMINATOR = 10000;

    // Yield pool
    uint256 public yieldPoolBalance;
    uint256 public yieldAPY = 400; // 4% APY (in basis points)

    // Events
    event SwapExecuted(
        address indexed user,
        string fromCurrency,
        string toCurrency,
        uint256 fromAmount,
        uint256 toAmount,
        uint256 fee,
        uint256 yield
    );

    event TokenRegistered(string currency, address tokenAddress);
    event ExchangeRateUpdated(string fromCurrency, string toCurrency, uint256 rate);
    event YieldDistributed(address indexed user, uint256 amount);

    constructor() Ownable(msg.sender) {}

    /**
     * @dev Register a new tokenized currency
     */
    function registerToken(
        string memory currencyCode,
        address tokenAddress
    ) external onlyOwner {
        require(currencyTokens[currencyCode] == address(0), "Currency already registered");
        require(tokenAddress != address(0), "Invalid token address");

        currencyTokens[currencyCode] = tokenAddress;
        tokenCurrencies[tokenAddress] = currencyCode;

        emit TokenRegistered(currencyCode, tokenAddress);
    }

    /**
     * @dev Update exchange rate (oracle in production)
     */
    function setExchangeRate(
        string memory fromCurrency,
        string memory toCurrency,
        uint256 rate
    ) external onlyOwner {
        require(currencyTokens[fromCurrency] != address(0), "From currency not registered");
        require(currencyTokens[toCurrency] != address(0), "To currency not registered");

        exchangeRates[fromCurrency][toCurrency] = rate;
        emit ExchangeRateUpdated(fromCurrency, toCurrency, rate);
    }

    /**
     * @dev Execute a cross-currency swap
     */
    function swap(
        string memory fromCurrency,
        string memory toCurrency,
        uint256 amount
    ) external nonReentrant returns (uint256 toAmount, uint256 yieldEarned) {
        require(currencyTokens[fromCurrency] != address(0), "From currency not supported");
        require(currencyTokens[toCurrency] != address(0), "To currency not supported");
        require(amount > 0, "Amount must be greater than 0");

        address fromToken = currencyTokens[fromCurrency];
        address toToken = currencyTokens[toCurrency];

        // Transfer tokens from user
        IERC20(fromToken).transferFrom(msg.sender, address(this), amount);

        // Calculate amounts
        uint256 rate = exchangeRates[fromCurrency][toCurrency];
        require(rate > 0, "Exchange rate not set");

        uint256 fee = (amount * protocolFee) / FEE_DENOMINATOR;
        uint256 netAmount = amount - fee;

        // Calculate converted amount (rate is scaled by 1e8)
        toAmount = (netAmount * rate) / 1e8;

        // Calculate yield (simplified - based on transfer time)
        yieldEarned = calculateYield(netAmount);

        // Mint/transfer output tokens
        NexusToken(toToken).mint(msg.sender, toAmount + yieldEarned);

        // Distribute yield from pool
        if (yieldEarned > 0 && yieldPoolBalance >= yieldEarned) {
            yieldPoolBalance -= yieldEarned;
            emit YieldDistributed(msg.sender, yieldEarned);
        }

        emit SwapExecuted(
            msg.sender,
            fromCurrency,
            toCurrency,
            amount,
            toAmount,
            fee,
            yieldEarned
        );

        return (toAmount, yieldEarned);
    }

    /**
     * @dev Calculate yield based on amount and APY
     */
    function calculateYield(uint256 amount) public view returns (uint256) {
        uint256 secondsPerYear = 31536000;
        uint256 transferSeconds = 3;
        return (amount * yieldAPY * transferSeconds) / (FEE_DENOMINATOR * secondsPerYear);
    }

    /**
     * @dev Add funds to yield pool
     */
    function addToYieldPool(uint256 amount) external {
        yieldPoolBalance += amount;
    }

    /**
     * @dev Update protocol fee
     */
    function setProtocolFee(uint256 newFee) external onlyOwner {
        require(newFee <= 500, "Fee cannot exceed 5%");
        protocolFee = newFee;
    }

    /**
     * @dev Update yield APY
     */
    function setYieldAPY(uint256 newAPY) external onlyOwner {
        require(newAPY <= 2000, "APY cannot exceed 20%");
        yieldAPY = newAPY;
    }

    /**
     * @dev Get exchange rate
     */
    function getRate(string memory fromCurrency, string memory toCurrency) external view returns (uint256) {
        return exchangeRates[fromCurrency][toCurrency];
    }
}

contracts/NexusToken.sol.content:
// SPDX-License-Identifier: Apache-2.0
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title NexusToken
 * @dev Tokenized currency representation on Hedera
 * Each token represents a fiat currency (MXN.x, PEN.x, USD.x, etc.)
 */
contract NexusToken is ERC20, Ownable {
    // Currency backing info
    string public currencyCode; // MXN, PEN, USD, etc.
    uint256 public backingRatio; // 100 = 1:1, 105 = 5% overcollateralized

    event Minted(address indexed to, uint256 amount);
    event Burned(address indexed from, uint256 amount);
    event BackingUpdated(uint256 newRatio);

    constructor(
        string memory _name,
        string memory _symbol,
        string memory _currencyCode
    ) ERC20(_name, _symbol) Ownable(msg.sender) {
        currencyCode = _currencyCode;
        backingRatio = 100;
    }

    function mint(address to, uint256 amount) external onlyOwner {
        _mint(to, amount);
        emit Minted(to, amount);
    }

    function burn(address from, uint256 amount) external onlyOwner {
        _burn(from, amount);
        emit Burned(from, amount);
    }

    function updateBackingRatio(uint256 newRatio) external onlyOwner {
        require(newRatio >= 80 && newRatio <= 120, "Invalid backing ratio");
        backingRatio = newRatio;
        emit BackingUpdated(newRatio);
    }

    function decimals() public view virtual override returns (uint8) {
        return 8; // Standard for Hedera tokens
    }
}

contracts/NexusVault.sol.content:
// SPDX-License-Identifier: Apache-2.0
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title NexusVault
 * @dev Yield-generating vault for Nexus Pay
 * Integrates with Bonzo Finance for DeFi yield
 */
contract NexusVault is Ownable, ReentrancyGuard {

    // User deposits
    mapping(address => mapping(string => uint256)) public deposits;
    mapping(address => mapping(string => uint256)) public depositTimestamp;

    // Vault totals
    mapping(string => uint256) public totalDeposits;

    // APY per currency
    mapping(string => uint256) public currencyAPY;

    // Supported currencies
    string[] public supportedCurrencies;

    // Events
    event Deposited(address indexed user, string currency, uint256 amount);
    event Withdrawn(address indexed user, string currency, uint256 amount, uint256 yield);
    event APYUpdated(string currency, uint256 newAPY);

    constructor() Ownable(msg.sender) {
        supportedCurrencies = ["MXN", "PEN", "USD", "EUR", "BRL"];

        currencyAPY["MXN"] = 420;
        currencyAPY["PEN"] = 380;
        currencyAPY["USD"] = 450;
        currencyAPY["EUR"] = 400;
        currencyAPY["BRL"] = 500;
    }

    function deposit(string memory currency, uint256 amount) external nonReentrant {
        require(isSupportedCurrency(currency), "Currency not supported");
        require(amount > 0, "Amount must be greater than 0");

        deposits[msg.sender][currency] += amount;
        depositTimestamp[msg.sender][currency] = block.timestamp;
        totalDeposits[currency] += amount;

        emit Deposited(msg.sender, currency, amount);
    }

    function withdraw(string memory currency) external nonReentrant returns (uint256 totalAmount) {
        require(isSupportedCurrency(currency), "Currency not supported");

        uint256 deposited = deposits[msg.sender][currency];
        require(deposited > 0, "No deposits for this currency");

        uint256 yieldEarned = calculateYield(msg.sender, currency);
        totalAmount = deposited + yieldEarned;

        deposits[msg.sender][currency] = 0;
        depositTimestamp[msg.sender][currency] = 0;
        totalDeposits[currency] -= deposited;

        emit Withdrawn(msg.sender, currency, deposited, yieldEarned);

        return totalAmount;
    }

    function calculateYield(address user, string memory currency) public view returns (uint256) {
        uint256 deposited = deposits[user][currency];
        if (deposited == 0) return 0;

        uint256 timestamp = depositTimestamp[user][currency];
        uint256 timeElapsed = block.timestamp - timestamp;

        uint256 apy = currencyAPY[currency];

        uint256 secondsPerYear = 31536000;
        return (deposited * apy * timeElapsed) / (10000 * secondsPerYear);
    }

    function getUserBalance(address user, string memory currency) external view returns (uint256) {
        return deposits[user][currency] + calculateYield(user, currency);
    }

    function setAPY(string memory currency, uint256 newAPY) external onlyOwner {
        require(isSupportedCurrency(currency), "Currency not supported");
        require(newAPY <= 2000, "APY cannot exceed 20%");

        currencyAPY[currency] = newAPY;
        emit APYUpdated(currency, newAPY);
    }

    function isSupportedCurrency(string memory currency) public view returns (bool) {
        for (uint256 i = 0; i < supportedCurrencies.length; i++) {
            if (keccak256(bytes(supportedCurrencies[i])) == keccak256(bytes(currency))) {
                return true;
            }
        }
        return false;
    }

    function getSupportedCurrencies() external view returns (string[] memory) {
        return supportedCurrencies;
    }

    function getTotalTVL() external view returns (uint256) {
        uint256 total;
        for (uint256 i = 0; i < supportedCurrencies.length; i++) {
            total += totalDeposits[supportedCurrencies[i]];
        }
        return total;
    }
}

